package main

import (
	"fmt"

	appruntime "socialpredict/internal/app/runtime"
	configsvc "socialpredict/internal/service/config"

	"gorm.io/gorm"
)

type startupMutationHooks struct {
	migrate      func(*gorm.DB) error
	verify       func(*gorm.DB) error
	seedUsers    func(*gorm.DB, configsvc.Service) error
	seedHomepage func(*gorm.DB, string) error
}

func runStartupMutations(db *gorm.DB, configService configsvc.Service, mode appruntime.StartupMutationMode, hooks startupMutationHooks) error {
	if mode.Writer {
		if hooks.migrate == nil || hooks.seedUsers == nil || hooks.seedHomepage == nil {
			return fmt.Errorf("startup writer hooks unavailable")
		}
		if err := hooks.migrate(db); err != nil {
			return fmt.Errorf("migrate database: %w", err)
		}
		if err := hooks.seedUsers(db, configService); err != nil {
			return fmt.Errorf("seed users: %w", err)
		}
		if err := hooks.seedHomepage(db, "."); err != nil {
			return fmt.Errorf("seed homepage: %w", err)
		}
		return nil
	}

	if hooks.verify == nil {
		return fmt.Errorf("startup schema verification hook unavailable")
	}
	if err := hooks.verify(db); err != nil {
		return fmt.Errorf("verify applied migrations: %w", err)
	}
	return nil
}

package runtime

import (
	"fmt"
	"os"
	"strings"
)

const (
	// StartupWriterEnv enables the one process role allowed to perform startup-owned DB writes.
	StartupWriterEnv = "STARTUP_WRITER"

	legacyStartupWriterEnv = "SP_STARTUP_WRITER"
)

// StartupMutationMode identifies whether this process may run startup-owned DB writes.
type StartupMutationMode struct {
	Writer bool
	Source string
}

// LoadStartupMutationModeFromEnv reads the explicit startup writer seam.
func LoadStartupMutationModeFromEnv() (StartupMutationMode, error) {
	for _, key := range []string{StartupWriterEnv, legacyStartupWriterEnv} {
		value, ok := os.LookupEnv(key)
		if !ok {
			continue
		}

		writer, err := parseStartupWriterFlag(value)
		if err != nil {
			return StartupMutationMode{}, fmt.Errorf("%s: %w", key, err)
		}
		return StartupMutationMode{Writer: writer, Source: key}, nil
	}

	return StartupMutationMode{Writer: false, Source: "default"}, nil
}

func parseStartupWriterFlag(value string) (bool, error) {
	switch strings.ToLower(strings.TrimSpace(value)) {
	case "1", "true", "yes", "on":
		return true, nil
	case "0", "false", "no", "off":
		return false, nil
	default:
		return false, fmt.Errorf("expected boolean startup writer flag, got %q", value)
	}
}

